231→const FOLDER_SPACING = { min: 0, max: 16, defaultValue: 2 };
232→const FOLDER_TREE_INDENT = { min: -8, max: 32, defaultValue: -8 };
233→const CHAT_PERCENT = { min: 30, max: 100, defaultValue: 70, legacyBaselinePx: LEGACY_BASELINE_PX };
234→const EDIT_PERCENT = { min: 30, max: 100, defaultValue: 60, legacyBaselinePx: LEGACY_BASELINE_PX };
235→const SIDEBAR_PERCENT = {
236→  min: 15,
237→  max: 45,
238→  defaultValue: 26,
239→  legacyBaselinePx: LEGACY_BASELINE_PX,
240→};
241→const SIDEBAR_PX = {
242→  min: Math.round(pxFromPercent(SIDEBAR_PERCENT.min)),
243→  max: Math.round(pxFromPercent(SIDEBAR_PERCENT.max)),
244→  defaultValue: Math.round(pxFromPercent(SIDEBAR_PERCENT.defaultValue)),
245→};
246→const AI_STUDIO_SIDEBAR_PX = {
247→  min: 240,
248→  max: 600,
249→  defaultValue: 280,
250→};
251→
252→const clampSidebarPx = (value: number) => clampNumber(value, SIDEBAR_PX.min, SIDEBAR_PX.max);
253→const normalizeSidebarPx = (value: number) => {
254→  if (!Number.isFinite(value)) return SIDEBAR_PX.defaultValue;
255→  // If the stored value looks like a legacy percent, convert to px first.
256→  if (value <= SIDEBAR_PERCENT.max) {
257→    const px = pxFromPercent(value);
258→    return clampSidebarPx(px);
259→  }
260→  return clampSidebarPx(value);
261→};
