 932→
 933→      try {
 934→        const alreadyGranted = await browser.permissions.contains({ origins: originPatterns });
 935→        if (alreadyGranted) return true;
 936→
 937→        const granted = await browser.permissions.request({ origins: originPatterns });
 938→        if (!granted) {
 939→          setWebsiteError(t('permissionDenied'));
 940→        }
 941→        return granted;
 942→      } catch (err) {
 943→        console.error('[Gemini Voyager] Failed to request permissions for custom website:', err);
 944→        setWebsiteError(t('permissionRequestFailed'));
 945→        return false;
 946→      }
 947→    },
